window.__QUIZ_DATA__=[{"id":"theory>Chemistry>2019>1>a","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL","question":"State the conditions necessary for the cracking of long-chain hydrocarbons to produce more gasoline.","images":[],"marking_scheme":"Conditions necessary for cracking  - High temperature  - High pressure  - Presence of catalyst","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>1>b","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"State two reasons why metallic objects are electroplated.","images":[],"marking_scheme":"Reasons why metallic objects are electroplated  - To increase its lustre  - It increases its resistance to corrosion  - It increases the electrical conductivity of the metal. For instance, if the metal is not a very good conductor, it may be silver plated. Silver is a very good conductor. In fact, the best conductor.   - It increases the hardness or strength of the metal.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>1>c>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS","question":"Explain briefly why calcium oxide cannot be used to dry hydrogen chloride gas.","images":[],"marking_scheme":"Calcium oxide (CaO) cannot be used to dry HCl gas because CaO reacts with the gas to give CaCl2.  CaO + 2HCl \u2192 CaCl2 + H2O","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>1>c>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS","question":"State one drying agent for hydrogen chloride gas.","images":[],"marking_scheme":"Drying agent for HCl gas are:  - H2SO4, silica gel","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>1>d","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Concentrated trioxonitrate (V) acid was added to a solution of iron (II) tetraoxosulphate (VI) and the mixture heated. The mixture turned from pale green to yellow with the evolution of a brown gas. Explain briefly these observations.","images":[],"marking_scheme":"FeSO4 + HNO3 \u2192 Fe(NO3)2 (pale green) + H2SO4  Fe(NO3)2 \u2192 FeO + NO2 (brown) + O2    The pale green colour is Fe(NO3)2 which decomposes on heating to liberate a reddish brown gas (NO2)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>1>e>i>I","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"I","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Write the equation for the reaction between zinc oxide and   - dilute tetraoxosulphate (VI) acid,","images":[],"marking_scheme":"- ZnO + H2SO4 \u2192 ZnSO4 + H2O","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>1>e>i>II","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"II","group":"","topic":"ACIDS, BASES AND SALTS : BASES","question":"Write the equation for the reaction between zinc oxide and   - sodium hydroxide solution.","images":[],"marking_scheme":"- ZnO + 2NaOH \u2192 Na2ZnO2 + H2O","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>1>e>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State which property of zinc oxide is shown by the reactions in (e)(i).","images":[],"marking_scheme":"ZnO behaves as amphoteric oxide i.e ZnO behaves as an acid and also as a base.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>1>f>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ISOTOPES","question":"Two isotopes of chlorine are 3517Cl and 3717Cl. State one similarity;","images":[],"marking_scheme":"Both isotopes have the same proton number.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>1>f>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ISOTOPES","question":"Two isotopes of chlorine are 3517Cl and 3717Cl. State one difference between the isotopes.","images":[],"marking_scheme":"Both isotopes differ in their number of neutron.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>1>g","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"g","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"State the two products formed when chlorine water is exposed to sunlight.","images":[],"marking_scheme":"Chlorine water is formed by passing chlorine in water.  Cl2 +H2O \u2192 HOCl + HCl  When chlorine water is exposed to sunlight, due to the unstable nature of HClO, it breaks to give hydrochlorine acid and liberates a gas which rekindles a glowing spirit i.e oxygen.  2HOCl \u2192 2HCl + O2 (in the presence of sunlight)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>1>h>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Consider the reaction represented by the following equation:  2H2S + SO2 \u2192 3S + H2O.  State the species that is undergoing oxidation;","images":[],"marking_scheme":"2H2S + SO2 \u2192 3S + H2O.  H2 undergoes oxidation.  Oxidation can be defined in terms of hydrogen as removal of hydrogen. Hence, hydrogen is removed from H2S to form S.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>1>h>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.","question":"Consider the reaction represented by the following equation:  2H2S + SO2 \u2192 3S + H2O.  State the oxidizing agent.","images":[],"marking_scheme":"SO2 is the oxidizing agent.  An oxidizing agent oxidizes other substance while itself is reduced. Reduction can be defined as removal of oxygen and oxygen is removed from SO2 to form H2O.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>1>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.","question":"What is meant by carbon-12 scale?","images":[],"marking_scheme":"Carbon - 12 - scale is a standard from which atomic masses of all nuclides are measured. It is used because it has a standard mass of 12u.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>1>j","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"j","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"State two properties of a chemical system in equilibrium.","images":[],"marking_scheme":"Properties of Chemical system in equilibrium  - It can only be achieved in a closed system.  - Rate of forward reaction is equal to the rate of backward reaction.  - It is dynamic in nature.  - The concentrations of all species present in the system remain constant as long as the reaction conditions are unchanged.  - Catalyst only affects the time taken to reach equilibrium but doesn't change the yield of the reaction.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>2>a>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"A hydrocarbon having the formula C10H22 was cracked to produce C6H14 and another hydrocarbon P.  Give the molecular formula of P.","images":[],"marking_scheme":"C10H22 \u2192 C6H14 + C4H8 (P)    P is C4H8 (Butene)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>2>a>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"A hydrocarbon having the formula C10H22 was cracked to produce C6H14 and another hydrocarbon P.    Draw the structures of two isomers of P.","images":["data:image/png;base64,"],"marking_scheme":"Isomers of P","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>2019>2>a>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"A hydrocarbon having the formula C10H22 was cracked to produce C6H14 and another hydrocarbon P.  Give a reason why P could be polymerized.","images":[],"marking_scheme":"P can be polymerized because  - It is unsaturated  - It may be symmetrical [but-2-ene]","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>2>b","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ORBITALS","question":"State the guiding principles which are used to explain the way electrons of the atoms of the elements are arranged in atomic orbitals.","images":[],"marking_scheme":"- AUFBAU'S PRINCIPLE: It states that electrons go into orbitals with lowest energy level before going into orbitals with higher energy level    - HUND'S RULE OF MAXIMUM MULTIPLICITY: This states that when filling electrons in the degenerate orbitals (orbitals with equal energy level), pairing is not allowed until each orbital has been singly filled.    - PAULI'S EXCLUSION PRINCIPLE: It states that no two electrons will have the same value for the four quantum numbers.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>2>c>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL BONDS : INTER MOLECULAR BONDING","question":"Consider each of the following substances: NaH, H2, H2S, NH4Cl.  Describe the nature of the intermolecular forces holding the units or molecules together in the condensed (liquid or solid) state.","images":[],"marking_scheme":"- NaH is held by covalent bond.  - H2S is held by hydrogen bond.  - H2 is held by covalent bond.  The force between these compounds will not be strong.  NH4Cl is held by covalent bond, electrovalent bond and dative bond.  In its solid state it sublimes, so the force of attraction between them is weak.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>2>c>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Explain briefly what happens when a sample of each of the substances is added to water.","images":[],"marking_scheme":"- When NaH reacts with water, a basic solution is formed which turns red litmus paper to blue.  Also, an effervescence occurs which ignites a glowing splint with a pop sound  - H2 is insoluble in water, so nothing happens  - H2S is a soluble gas due to the presence of hydrogen bond.  - NH4Cl is extremely soluble in water. It gives an acidic solution in water. The products are NH4OH and HCl. HCl is a strong acid while NH4OH is a weak base.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>2>c>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE REACTIONS","question":"Write the chemical equations of any reactions occurring or of any equilibria established.","images":[],"marking_scheme":"- NaH + H2O \u2192 NaOH + H2  - NH4Cl + H2O \u21cc NH4OH + HCl","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>2>d>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"Element J has the following electron configuration: 1s22s22p63s2.  How many unpaired electrons can be found in J?","images":["data:image/png;base64,"],"marking_scheme":"J : 1s22s22p63s2.    O unpaired electrons i.e no unpaired electron.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>2>d>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Element J has the following electron configuration: 1s22s22p63s2.  State whether J would be a good oxidizing or reducing agent.","images":[],"marking_scheme":"J is a reducing agent because it is a metal. It ionizes by electron loss.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>2>d>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.","question":"Element J has the following electron configuration: 1s22s22p63s2.  Give a reason for the answer in 2(d)(ii).","images":[],"marking_scheme":"It is because J is a metal and it will ionize by electron loss to attain an octet configuration.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>a>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"In the Solvay process, explain briefly with equations the functions of this substance:  limestone.","images":[],"marking_scheme":"Solvay process is the production of Na2CO3 which uses CaCO3, NaCl and NH3.    The function of limestone (CaCO3): It generates CO2 by decomposing it   CaCO3 \u2192 CaO + CO2  The CO2 produced then dissolves in H2O to give trioxocarbonate IV acid  H2O + CO2 \u2192 H2CO3  Therefore, the function of CaCO3 is to produce carbon IV oxide (CO2)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>3>a>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"In the Solvay process, explain briefly with equations the functions of this substance:  Ammonia.","images":[],"marking_scheme":"The function of Ammonia in Solvay process:  NH3 reacts with the CO2 produced to give Ammonium hydrogen trioxocarbonate IV   NH3 + CO2 \u2192 NH4HCO3  NH4HCO3 then reacts with NaCl to give sodium hydrogen trioxocarbonate IV  NH4HCO3 + NaCl \u2192 NaHCO3 + NH4Cl","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>3>b>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"Write a chemical equation for the fermentation of glucose.","images":[],"marking_scheme":"C6H12O6 \u2192 2C2H5OH + 2CO2  \u21d2 (Glucose) \u2192 (ethanol) + (carbon IV oxide)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>b>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Explain briefly why a tightly-corked glass bottle filled to the brim with fresh palm-wine shatters on standing for some time.","images":[],"marking_scheme":"Fermentation occurs in the wine which brings out CO2 gas. The gas builds up as this process continues. Since fluids cannot be compressed, the pressure of the gas increases and since there is no room for it in the tightly-corked glass filled to the brim, the bottle shatters.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>3>c>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"Consider the following metals: Na, Fe, K and Cu.  Arrange the metals in order of increasing reactivity.","images":[],"marking_scheme":"Metals: Na, Fe, K, Cu  Increasing reactivity: From the electrochemial series, metals up in the series are more reactive than those ones below.  \u2234 Increase reactivity Cu, Fe, Na, K.  Electrochemical series  k+  Na+  Ca2+  Mg2+  Al3+  Zn2+  Fe2+  Sn2+ &nbsp &nbsp &nbsp \u2191 Increasing reactivity  Pb2+  H+  Cu2+  Hg+  Ag+  Au+","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2019>3>c>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS","question":"Consider the following metals: Na, Fe, K and Cu.  Which of the metals will react with cold water?","images":[],"marking_scheme":"Group 1 elements react with cold water because they are very reactive i.e the most electropositive metals.  K and Na  They both belong to group 1.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>c>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Consider the following metals: Na, Fe, K and Cu.  Which of the metals could form coloured salts?","images":[],"marking_scheme":"Transition metals have ability to form coloured ions due to their variable oxidation state. They are d-block elements.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>d>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"What is a redox reaction?","images":[],"marking_scheme":"Redox reaction is a reaction that involves both oxidation and reduction processes. Both processes occur simultaneously.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>3>d>ii>I","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Identify which of the following reaction equations are redox.  - 2Na + Cl2 \u2192 2NaCl","images":["data:image/png;base64,"],"marking_scheme":"-   Oxidation is the addition of electronegative element. Chlorine an electronegative element is added to sodium.  Reduction is the addition of electropositive element. Sodium an electropositive element is added to chlorine.  Also, Na \u2192 Na+. There is increase in oxidation state of sodium from 0 to +1. This is oxidation Cl2 \u2192 l-. There is decrease in oxidation state of chlorine from 0 to -1. This is reduction.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>3>d>ii>II","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Identify which of the following reaction equations are redox.  - AgCl + 2NH3 \u2192 [Ag(NH3)2]Cl","images":[],"marking_scheme":"- AgCl + 2NH3 \u2192 [Ag(NH3)2]Cl  This is a combination reaction. Two reactants form one product.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>3>d>ii>III","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Identify which of the following reaction equations are redox.  - C2H2 + H2 \u2192 C2H4","images":[],"marking_scheme":"- C2H2 + H2 \u2192 C2H4  This is an addition reaction. Hydrogenation of ethyne to give ethene.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>d>ii>IV","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"IV","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Identify which of the following reaction equations are redox.  - HCl + KOH \u2192 KCl + H2O","images":[],"marking_scheme":"- HCl + KOH \u2192 KCl + H2O  This is a neutralization reaction. A reaction between an acid and a base to form salt and water.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>3>d>ii>V","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"V","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Identify which of the following reaction equations are redox.  - 2FeCl3 + 2Kl \u2192 2FeCl2 + 2KCl + I2","images":[],"marking_scheme":"- 2FeCl3 + 2KI \u2192 2FeCl2 + 2KCl + I2  Fe3+ \u2192 Fe2+ [Decrease in oxidation number from +3 to +2]. This is a reduction process.  I- \u2192 I2 [Increase in oxidation from -1 to 0]. This is oxidation.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>3>d>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Give a reason for each of the answer in 3(d)(ii).","images":[],"marking_scheme":"Na \u2192 Na+  This is increase in oxidation state of sodium from 0 to +1. The proces is called Oxidation.  Cl2 \u2192 Cl-  There is decrease in the oxidation state of chlorine from 0 to -1. This is called reduction.  Also in V  Fe3+ \u2192 Fe2+  There is decrease in oxidtion number of iron from +3 to +2, which is a reduction process  I- \u2192 I2  There is increase in oxidation number of iodine from -1 to 0. This is oxidation.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>3>d>iv","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iv","group":"","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Write balanced equations of the half reactions for any two of the redox reactions in 3(d)(ii).","images":[],"marking_scheme":"Na + Cl2 \u2192 NaCl  Na \u2192 Na+ [oxidation]  Na \u2192 Na+ + e- [Balance charge]  Also,   Cl2 \u2192 Cl- [Reduction]  Cl2 \u2192 2Cl- [Balance atom]  Cl2 + 2e- \u2192 2Cl- [Balance charge]  FeCl3 + KI \u2192 FeCl2 + KCl + I2  Fe3+ \u2192 Fe2+ [Reduction]  Fe3+ + e- \u2192 Fe2+ [Balance charge]  And  I- \u2192 I2 [Oxidation]  2I- \u2192 I2 [Balance atom]  2I- \u2192 I2 + 2e- [Balance charge]  FeCl3 + KI \u2192 FeCl2 + KCl + I2  Fe3+ \u2192 Fe2+ [Reduction]  Fe3+ + e- \u2192 Fe2+ [Balance charge]  And  I- \u2192 I2 [Oxidation]  2I- \u2192 I2 [Balance atom]  2I- \u2192 I2 + 2e- [Balance charge]","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>4>a>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"The following reaction scheme is an illustration of the contact process.      Name X and Y.","images":["data:image/png;base64,"],"marking_scheme":"S(s) + O2(g) \u2192 SO2(g)  \u2234 X = oxygen gas  Y = sulphur","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>4>a>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"The following reaction scheme is an illustration of the contact process.    Write balanced chemical equation for each of the processes I, II, III and IV.","images":["data:image/png;base64,"],"marking_scheme":"S(s) + O2(g) \u2192 SO2(g) . . . I    2SO2 + O2 \u2192 2SO3 . . . II (with the presence of Y2O5)    SO3+ H2SO4 \u2192 H2S2O7 . . . III    H2S2O7 + H2O \u2192 2H2SO4 . . . IV","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>4>a>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"The following reaction scheme is an illustration of the contact process.    Name the catalyst used in process II.","images":["data:image/png;base64,"],"marking_scheme":"V2O5 is the catalyst in II called Vanadium V oxide.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>4>a>iv","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"The following reaction scheme is an illustration of the contact process.    Using Le Chatelier's principle, explain briefly why increasing the temperature would not favour the reaction in II.","images":["data:image/png;base64,"],"marking_scheme":"2SO2 + O2 \u21cc 2SO3  The reaction is an exothermic reaction. Increase in temperature would favour the reactant which is the endothermic side and not the product which is exothermic.  NB: Increase in temperature usually favours a side which endothermic while decrease in temperature favours a side which is exothermic .","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2019>4>a>v","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State two uses of SO2.","images":[],"marking_scheme":"Uses of SO2  - It is used as a reducing agent.  - It is used as a bleaching agent. It bleaches by reduction while chlorine bleaches by oxidation.  - It is used in producing important compounds like H2SO4.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>4>b","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"Consider the following reaction equation:  2H2(g) + O2(g) \u2192 2H2O(g).  Calculate the volume of unused oxygen gas when 40cm3 of hydrogen gas is sparked with 30cm3 of oxygen gas.","images":[],"marking_scheme":"2H2 + O2 \u2192 2H2O  Mole ratio 2 &nbsp &nbsp 1 &nbsp &nbsp 2  Vol. ratio 40 &nbsp &nbsp 20 &nbsp &nbsp 40  Volume of unused oxygen : (30 - 20)cm3  \u21d2 10cm3  This is because the available volume of oxygen is 30cm3 but 20cm3 is used in the reaction according to the volume ratio.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>4>c>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"Calcium carbonate of mass 1.0g was heated until there was no further change.  Write an equation for the reaction which took place.","images":[],"marking_scheme":"CaCO3 \u2192 CaO + CO2","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>4>c>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calcium carbonate of mass 1.0g was heated until there was no further change.  Calculate the mass of the residue.    Leave your answer in two decimal places 'a.bc'","images":[],"marking_scheme":"NoofmoleofCaCO3=massmolar mass  Molar mass of CaCO3 = 40 + 12 + (16 \u00d7 3) = 100gmol-1  No.ofmoleofCaCO3=1g100gmol-1 = 0.01 mole  From the balanced equation  1 mole of CaCO3 \u2192 1 mole of CaO  0.01 mole of CaCO3 \u2192 x  x = 0.01 mole of CaO  Sincenoofmole=massmolar mass  0.01=m40+16  0.01=m56  m = 0.56g","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>4>c>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calcium carbonate of mass 1.0g was heated until there was no further change.  Calculate the volume of the gas evolved at s.t.p.    Leave your answer in whole number 'abc'","images":[],"marking_scheme":"From the balanced equation  1 mole of CaCO3 \u2192 1 mole of CO2  0.01 mole of CaCO3 \u2192 y  \u2234 y = 0.01 mole of CO2  NoofmoleofCO2=VolumeMolar Volume  0.01=Vol22.4  Vol = 0.224 dm3  Vol = 224cm3","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>4>c>iv","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iv","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calcium carbonate of mass 1.0g was heated until there was no further change.  What would be the volume of the gas measured at 15\u00b0C and 760mmHg?  [C = 12.0, O = 16.0, Ca = 40.0, Molar volume of a gas at s.t.p. = 22.4 dm3]    Leave your answer in one decimal place 'abc.d'","images":[],"marking_scheme":"V1 = 224cm3, V2 = ?  P1 = 760mmHg, P2 = 760mmHg  T1 = 273K, T2 = 15\u00b0C + 273 = 288K  UsingV1P1T1=V2P2T2  224 \u00d7 760273=V2 \u00d7 760288  V2=224 \u00d7 760 \u00d7 288273 \u00d7 760  V2 = 236.3cm3","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2019>5>a>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"Draw and label a diagram to illustrate the preparation and collection of dry chlorine gas in the laboratory.","images":["data:image/png;base64,"],"marking_scheme":"Chlorine is prepared by the oxidation of HCl with KMnO4  16HCl + 2KMnO4 \u2192 2KCl + 2MnCl2 + 5Cl2 + 8H2O        H2O is placed in the mechanism in order to remove impurities.  H2SO4 helps dry the chlorine gas.  The gas is then collected by downward delivery because it is denser than air.","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>2019>5>a>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"State two uses of chlorine.","images":[],"marking_scheme":"- It is used as a disinfectant.  - It is used as a bleaching agent. It bleaches by oxidation.  - It is used in killing germs.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>5>b","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN","question":"Describe the preparation of hydrogen from water gas.","images":[],"marking_scheme":"Water gas is gotten by passing steam with red hot coke.  C + H2O(g) \u2192 [CO + H2 ] \u2192 Water gas","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2019>5>c>i","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Name the chief ore of aluminium.","images":[],"marking_scheme":"Ores of Aluminium are Bauxite and cryolite. The chief ore is bauxite (Al2O3.3H2O).","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>5>c>ii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Why is the ore purified?","images":[],"marking_scheme":"The ore is purified in order to remove the earth impurities. The purification is done by washing the ore in water. It is then treated with NaOH  Al2O3.3H2O + NaOH \u2192 NaAl(OH)4  The sodium tetrahydroxoaluminate solution (NaAl(OH)4) is cooled and \"seeded\" with some previously produced aluminium hydroxide. This provides something for the new aluminium hydroxide to precipitate around  NaAl(OH)4 \u2192 Al(OH)3 + NaOH  Alumina (Aluminium oxide) is made by heating Al(OH)3 to a high temperature  2Al(OH)3 \u2192 Al2O3 + 3H2O  The aluminium oxide is electrolysed in molten cryolite (Na3AlF6)","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2019>5>c>iii","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Name the electrode used in the electrolysis.","images":[],"marking_scheme":"The electrode used in the electrolysis is carbon (graphite).","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2019>5>c>iv","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Give one reason why cryolite, Na3AlF6, is added to the electrolyte.","images":[],"marking_scheme":"Reason for adding cryolite  - It is used to dissolve the aluminium oxide since it doesn't dissolve in water.  - It is added to reduce energy cost involved in extracting aluminium since aluminium has a very high melting point.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2019>5>d","subject":"Chemistry","year":"2019","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL","question":"Name three products obtained directly from the destructive distillation of coal.","images":[],"marking_scheme":"Products of Destructive Distillation of Coal  - Coke  - Coal gas  - Coal tar  - Ammoniacal liquor   - Coal oil","marks":"2","difficulty":"3"}];